+        );
+        assert_eq!(frame.column_names(), vec!["id", "amount"]);
+        assert_eq!(
+            frame.column("amount").unwrap().values(),
+            &[Scalar::Float64(1.25), Scalar::Float64(2.5)]
+        );
+    }
